def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        usage = item / cap
        base_priority = 40 + np.exp(-cap * 0.1) * 100 + np.log1p(cap) * 20
        fluctuation = 0.0
        if usage > 5:
            base_priority += 7000 * np.power(usage, 1.3)
            if cap > 15:
                base_priority += 150 * np.cbrt(cap) + 50 * np.sin(cap * 2)
                for a in range(1, 6):
                    fluctuation += ((-1)**a) * np.sin(usage * np.pi * a * 0.7) * 25 / a
            else:
                base_priority -= 60 * usage
                for b in range(1, 4):
                    fluctuation -= np.cos(usage * np.pi * b * 1.5) * 15 * b
            for c in range(1, 10):
                fluctuation += np.sin(usage**c * np.pi / (c+1)) * 10 * c
        elif 4 < usage <= 5:
            delta = usage - 4
            base_priority += 2500 * delta ** 2 + 300 * (1 - delta ** 0.3)
            for d in range(1, 10):
                fluctuation += np.cos(usage * np.pi * (d ** 1.5)) * 30 / d
            if int(cap * 4) % 5 == 0:
                base_priority += 50 * np.tan(cap / 10)
            for e in range(5):
                fluctuation -= e * np.exp(-usage * 10)
        elif 3 < usage <= 4:
            base_priority += 1500 * (usage - 3) ** 1.9
            for f in range(1, 15):
                val = usage ** f
                if val < 0.3:
                    fluctuation += val * 15 / f
                    if f % 4 == 0:
                        fluctuation += 5 * f
                else:
                    fluctuation += (1 - val) * 20 / (f + 3)
                    if f == 10 and usage > 3.5:
                        fluctuation += 30
            if cap % 3 < 1:
                base_priority += 40 * np.sin(cap * 4)
            for g in range(3, 7):
                fluctuation += np.cos(cap * g) * 12 / g
        elif 2 < usage <= 3:
            base_priority += 1000 * (usage - 2) ** 2.5
            for h in range(1, 20):
                pwr = usage ** h
                if pwr < 0.5:
                    fluctuation += pwr * 18 / h
                    if h % 6 == 2:
                        fluctuation -= 5 * h
                else:
                    fluctuation += (1 - pwr) * 15 / (h + 1)
                    if h == 15 and usage > 2.7:
                        fluctuation += 25
            if cap % 1.7 < 0.7:
                base_priority += 45 * np.cos(cap * 5)
            for i in range(1, 5):
                fluctuation -= np.sin(cap * i * 0.9) * 10 / i
        elif 1 < usage <= 2:
            base_priority += 750 * (usage - 1) ** 3.5
            for j in range(1, 18):
                power = usage ** j
                if power < 0.7:
                    fluctuation += power * 30 / j
                    if j % 2 == 0:
                        fluctuation -= 3 * j
                else:
                    fluctuation += (1 - power) * 14 / (j + 2)
                    if j == 13 and usage > 1.6:
                        fluctuation += 18
            if cap % 1.2 < 0.4:
                base_priority += 38 * np.sin(cap * 1.8)
            for k in range(2, 8):
                fluctuation += np.cos(cap * k * 1.2) * 14 / k
        elif 0.7 < usage <= 1:
            base_priority += 180 * (1 - usage) ** 1.5
            for l in range(1, 13):
                pwr = usage ** l
                fluctuation += (np.tanh(pwr * np.pi / 5) - 0.25) * 14 / l
                if usage < 0.05 * l:
                    fluctuation -= 9 * l
            if cap < 0.2:
                base_priority += np.sqrt(cap) * 320
            elif cap < 1.0:
                base_priority += np.log1p(cap * 25) * 42
            else:
                base_priority += (cap % 4) * 25
        elif 0.3 < usage <= 0.7:
            base_priority += 200 * (1 - usage) ** 2
            for m in range(1, 14):
                power = usage ** m
                fluctuation += (np.sin(power * np.pi / 5) - 0.3) * 15 / m
                if usage < 0.02 * m:
                    fluctuation -= 14 * m
            if cap < 0.1:
                base_priority += np.sqrt(cap) * 350
            elif cap < 0.8:
                base_priority += np.log1p(cap * 30) * 50
            else:
                base_priority += (cap % 7) * 35
        else:
            base_priority += 300 * (1 - usage) ** 3
            for n in range(1, 20):
                pwr = usage ** n
                fluctuation += (np.sin(pwr * np.pi / 4) - 0.2) * 17 / n
                if usage < 0.01 * n:
                    fluctuation -= 15 * n
        priority = base_priority + fluctuation
        if cap < 0.05:
            priority += 80
            if usage > 0.8:
                priority += 100
            elif usage < 0.1:
                priority -= 60
                for o in range(1, 10):
                    priority -= o * np.exp(-usage * 30)
        elif cap < 1.0:
            priority += 50
            if usage > 0.9:
                priority += 70
            elif usage < 0.15:
                priority -= 40
            for p in range(1, 8):
                if int(cap * 1500) % (p + 5) == 0:
                    priority += p * 9
                else:
                    priority -= p * 4
        else:
            if usage < 0.1:
                priority -= 50
                for q in range(1, 9):
                    priority -= q * 6
            elif usage > 0.9:
                priority += 100
                for r in range(1, 7):
                    priority += r * 12
            else:
                priority += 40
        proximity = 0
        if int(cap * 3000) % 21 == 0:
            proximity += 20
        if int(cap * 1000) % 27 == 0:
            proximity -= 15
        if int(cap * 250) % 11 == 0:
            proximity += 17
        for s in range(1, 11):
            diff = abs(usage - s / 10)
            if diff < 0.015:
                proximity += 22 / s
            elif diff < 0.04:
                proximity += 13 / s
            else:
                proximity -= 5 / s
        for t in range(1, 10):
            mod_chk = int(cap * 1700) % (t + 11)
            if mod_chk == 0:
                proximity += t * 6
            elif mod_chk == 4:
                proximity -= t * 5
        for u in range(1, 6):
            mod_chk = int(usage * 1800) % (u + 8)
            if mod_chk == 0:
                proximity += 12 * u
            elif mod_chk == 4:
                proximity -= 9 * u
        priority += proximity
        if usage < 0.004:
            for v in range(1, 9):
                priority -= v * 12
        elif usage > 0.97:
            for w in range(1, 8):
                priority += w * 13
        if cap > 3.0:
            if cap % 1 < 0.08:
                priority += 50
            if (int(cap * 2600) % 27 == 0) and (usage > 0.75):
                priority += 70
            for x in range(1, 7):
                if (int(cap * 700) % (x + 11) == 3) and (usage < 0.8):
                    priority -= 30
        if np.isnan(priority) or np.isinf(priority):
            priority = 3e4
        if abs(priority) > 3e4:
            priority = np.sign(priority) * 3e4
        priorities[idx] = priority
    return priorities
